import json
import os

class GenericAdapter:
    def __init__(self, label_map, pixel_per_um):
        self.label_map = label_map # e.g., {1: 0, 2: 1}
        self.scale = pixel_per_um

    def coco_to_yolo(self, bbox, img_w, img_h):
        # COCO: [x_min, y_min, width, height] -> YOLO: [x_c, y_c, w, h] normalized
        x, y, w, h = bbox
        return [(x + w/2)/img_w, (y + h/2)/img_h, w/img_w, h/img_h]

    def transform_coco_to_standard(self, coco_json_path, img_dir, out_dir):
        with open(coco_json_path) as f: data = json.load(f)
        os.makedirs(os.path.join(out_dir, 'labels'), exist_ok=True)
        img_map = {i['id']: i for i in data['images']}
        for ann in data['annotations']:
            img = img_map[ann['image_id']]
            yolo_box = self.coco_to_yolo(ann['bbox'], img['width'], img['height'])
            label_path = os.path.join(out_dir, 'labels', f"{os.path.splitext(img['file_name'])[0]}.txt")
            with open(label_path, 'a') as lf:
                lf.write(f"{self.label_map[ann['category_id']]} {' '.join([f'{c:.6f}' for c in yolo_box])}\n")

