def safe_batch_inference(self, image, bboxes, initial_batch_size):
    current_bs = initial_batch_size
    while current_bs >= 1:
        try:
            return self._execute_sam2_inference(image, bboxes, batch_size=current_bs)
        except RuntimeError as e:
            if 'out of memory' in str(e).lower():
                torch.cuda.empty_cache()
                old_bs = current_bs
                current_bs //= 2
                logging.warning(f'OOM detected. Reducing batch size from {old_bs} to {current_bs}')
                if current_bs < 1: raise e
            else: raise e
