import exifread
import zipfile

def verify_zip_assets(zip_path):
    blacklist = ['GPS', 'SerialNumber', 'Artist', 'Software']
    report = {'violations': [], 'status': 'PASS'}
    with zipfile.ZipFile(zip_path, 'r') as z:
        for name in z.namelist():
            if name.lower().endswith(('.jpg', '.tiff')):
                with z.open(name) as f:
                    tags = exifread.process_file(f, stop_tag='UNDEF')
                    for tag in tags.keys():
                        if any(s in tag for s in blacklist):
                            report['violations'].append({'file': name, 'tag': tag})
                            report['status'] = 'FAIL'
    return report
